const data = $input.first().json;
const request = $('Prepare Input').item.json;

const safeNumber = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const num = Number(value);
  return Number.isFinite(num) ? num : null;
};

const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const money = (value) => {
  const num = safeNumber(value);
  if (num === null) return 'N/A';
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    maximumFractionDigits: 0,
  }).format(num);
};

const integer = (value) => {
  const num = safeNumber(value);
  if (num === null) return 'N/A';
  return new Intl.NumberFormat('en-US', { maximumFractionDigits: 0 }).format(num);
};

const percent = (value, digits = 1) => {
  const num = safeNumber(value);
  if (num === null) return 'N/A';
  return `${(num * 100).toFixed(digits)}%`;
};

const points = (value, digits = 1) => {
  const num = safeNumber(value);
  if (num === null) return 'N/A';
  const scaled = num * 100;
  const sign = scaled > 0 ? '+' : '';
  return `${sign}${scaled.toFixed(digits)} pts`;
};

const directionalPct = (value, label) => {
  const num = safeNumber(value);
  if (num === null) return `flat ${escapeHtml(label)}`;
  const direction = num > 0 ? 'up' : num < 0 ? 'down' : 'flat';
  return `${direction} ${Math.abs(num * 100).toFixed(0)}% ${escapeHtml(label)}`;
};

const makeSection = (title, body) => `
  <div class="section">
    <h2>${escapeHtml(title)}</h2>
    ${body}
  </div>
`;

const supplierId = data.supplier_id || request.supplierId;
const supplierName = data.supplier_name || `Supplier ${supplierId}`;
const teamName = request.teamName || `${supplierName} team`;
const currentMonth = data.current_month_label || 'Last Completed Month';
const priorMonth = data.prior_month_label || 'Prior month';
const priorYearMonth = data.prior_year_month_label || 'Prior year month';
const dashboardUrl = request.dashboardUrl;
const unfindablesNotes = request.unfindablesNotes;
const adHocNotes = request.adHocNotes;
const subject = `Ad Hoc Supplier Pre-Read | ${supplierName} (${supplierId}) | ${currentMonth}`;

let bodySections = [];
let warningBlock = '';

if (!data.supplier_exists) {
  warningBlock = `<div class="warning">No supplier in the selected portfolio matched SuID <strong>${escapeHtml(supplierId)}</strong>. Check the ID or portfolio owner filter before using this pre-read.</div>`;
}

const introHtml = `
  <p>Hi ${escapeHtml(teamName)},</p>
  <p>I’m looking forward to meeting with you today and aligning on future goals!</p>
  <p><strong>Brief Agenda:</strong><br/>I included your ${escapeHtml(currentMonth)} performance below as a reference for you. I’d love to walk through this performance recap to highlight additional areas we can partner together in 2026.</p>
`;

bodySections.push(makeSection(
  `Business Review ${currentMonth}`,
  `
    <p>${escapeHtml(currentMonth)} landed at <strong>${money(data.current_wsc)}</strong> in WSC which was <strong>${directionalPct(data.mom_wsc_pct, 'MoM')}</strong> and <strong>${directionalPct(data.yoy_wsc_pct, 'YoY')}</strong>.</p>
    <ul>
      <li>${escapeHtml(priorMonth)} WSC: <strong>${money(data.prior_month_wsc)}</strong></li>
      <li>${escapeHtml(priorYearMonth)} WSC: <strong>${money(data.prior_year_wsc)}</strong></li>
    </ul>
  `
));

bodySections.push(makeSection(
  'Traffic',
  `
    <p><strong>${integer(data.current_visits)}</strong> SKU Visits (${directionalPct(data.mom_visits_pct, 'MoM')}, ${directionalPct(data.yoy_visits_pct, 'YoY')})</p>
    <p><strong>${percent(data.current_cvr, 2)}</strong> CVR (${points(data.mom_cvr_change, 2)} vs ${escapeHtml(priorMonth)}, ${points(data.yoy_cvr_change, 2)} vs ${escapeHtml(priorYearMonth)})</p>
  `
));

bodySections.push(makeSection(
  'Availability',
  `
    <p>${escapeHtml(currentMonth)} Global Availability: <strong>${percent(data.current_availability)}</strong></p>
    <ul>
      <li>MoM change: <strong>${points(data.mom_availability_change)}</strong></li>
      <li>YoY change: <strong>${points(data.yoy_availability_change)}</strong></li>
      <li>MRPI: <strong>${percent(data.current_mrpi)}</strong> (${points(data.mom_mrpi_change)} MoM)</li>
      <li>WSI: <strong>${percent(data.current_wsi)}</strong> (${points(data.mom_wsi_change)} MoM)</li>
    </ul>
  `
));

bodySections.push(makeSection(
  'Wayfair Professional',
  `
    <p>Use the linked <strong>monthly_supplier_report</strong> dashboard for the B2B share and discount context before the meeting.</p>
  `
));

bodySections.push(makeSection(
  'Advertising',
  `
    <p>Use the dashboard’s <strong>Performance Marketing</strong> section to review spend, attributed WSC, and ROAS before sending this externally.</p>
  `
));

bodySections.push(makeSection(
  `Dropship Performance (${currentMonth})`,
  `
    <p>Use the dashboard’s <strong>L3M Operations Metrics</strong> tile to pull fill rate, OTS, OTD, and related operations callouts for the meeting narrative.</p>
  `
));

bodySections.push(makeSection(
  'Promotions',
  `
    <p>Use this section to add any live promotion questions or frequency / source-room follow-ups before sharing the draft.</p>
  `
));

bodySections.push(makeSection(
  'Assortment',
  `
    <p>Reference <strong>Active SKU Count LCM</strong>, <strong>Top SKUs</strong>, and <strong>Top Supplier Parts</strong> in the dashboard for assortment talking points.</p>
  `
));

if (unfindablesNotes) {
  bodySections.push(makeSection(
    'Unfindables',
    `<p>${escapeHtml(unfindablesNotes)}</p>`
  ));
}

bodySections.push(makeSection(
  'Ad Hoc',
  adHocNotes
    ? `<p>${escapeHtml(adHocNotes).replace(/\n/g, '<br/>')}</p>`
    : '<p>Add one-off notes, asks, or follow-ups here before sharing the draft.</p>'
));

const dashboardSection = `
  <div class="dashboard-box">
    <strong>Dashboard reference:</strong>
    <a href="${escapeHtml(dashboardUrl)}" target="_blank">monthly_supplier_report</a>
    <div class="small">Source dashboard slug: hxVugArzfrkD6YuI94A2dq</div>
  </div>
`;

const htmlBody = `
<!DOCTYPE html>
<html>
  <head>
    <meta charset="UTF-8" />
    <style>
      body {
        font-family: Arial, sans-serif;
        color: #1f2933;
        line-height: 1.55;
        margin: 0;
        padding: 24px;
      }
      .header {
        background: #7F187F;
        color: #fff;
        border-radius: 8px;
        padding: 16px 18px;
        margin-bottom: 18px;
      }
      h1 {
        margin: 0;
        font-size: 24px;
      }
      h2 {
        color: #7F187F;
        border-bottom: 2px solid #ead6ea;
        padding-bottom: 4px;
        margin-top: 28px;
        margin-bottom: 10px;
      }
      .section p {
        margin: 8px 0;
      }
      ul {
        margin-top: 8px;
      }
      .warning {
        background: #fff4db;
        color: #7c5a00;
        border: 1px solid #f0c36d;
        border-radius: 8px;
        padding: 12px 14px;
        margin-bottom: 18px;
      }
      .dashboard-box {
        margin-top: 22px;
        padding: 12px 14px;
        border: 1px solid #d9e2ec;
        background: #f8fbfd;
        border-radius: 8px;
      }
      a {
        color: #7F187F;
      }
      .small {
        color: #7b8794;
        font-size: 12px;
        margin-top: 6px;
      }
    </style>
  </head>
  <body>
    <div class="header">
      <h1>Ad Hoc Supplier Pre-Read</h1>
      <div>Supplier: <strong>${escapeHtml(supplierName)}</strong> (SuID ${escapeHtml(supplierId)})</div>
      <div>Reporting month: <strong>${escapeHtml(currentMonth)}</strong></div>
    </div>
    ${warningBlock}
    ${introHtml}
    ${bodySections.join('\n')}
    ${dashboardSection}
  </body>
</html>`;

return [{
  json: {
    sendTo: request.recipientEmail,
    subject,
    message: htmlBody,
    previewHtml: htmlBody,
  },
}];
